SELECT
count( RES.ID_ )
FROM
ACT_RE_MODEL RES


        and RES.KEY_ = #{modelBo.modelKey}


        and RES.NAME_ LIKE concat('%',#{modelBo.modelName},'%')


        and RES.CATEGORY_ in

            #{category}



        and RES.CATEGORY_ in

            #{category}



        and RES.CATEGORY_ =
        #{modelBo.wfCategory}


        and RES.CATEGORY_ =
        #{modelBo.WorkOrderCategory}


        AND RES.VERSION_ =
        (SELECT
        max( VERSION_ )
        FROM
        ACT_RE_MODEL
        WHERE
        KEY_ = RES.KEY_
        )

    AND RES.TENANT_ID_ = #{tenantId}

SELECT RES.ID_, RES.REV_, RES.NAME_, RES.KEY_, RES.CATEGORY_, RES.CREATE_TIME_, RES.LAST_UPDATE_TIME_, RES.VERSION_, RES.META_INFO_, RES.DEPLOYMENT_ID_, RES.EDITOR_SOURCE_VALUE_ID_, RES.EDITOR_SOURCE_EXTRA_VALUE_ID_, RES.TENANT_ID_ FROM ACT_RE_MODEL RES
and RES.KEY_ = #{modelBo.modelKey}
and RES.NAME_ LIKE concat('%',#{modelBo.modelName},'%')
and RES.CATEGORY_ in
#{category}
and RES.CATEGORY_ in
#{category}
and RES.CATEGORY_ = #{modelBo.wfCategory}
and RES.CATEGORY_ = #{modelBo.WorkOrderCategory}
AND RES.VERSION_ = (SELECT max( VERSION_ ) FROM ACT_RE_MODEL WHERE KEY_ = RES.KEY_ )
AND RES.TENANT_ID_ = #{tenantId}
ORDER BY RES.CREATE_TIME_ DESC
